/*
 * ldexpf() test harness -- prints (input_hex, exponent, output_hex) triples.
 *
 * Build two versions:
 *   1. Linked with optimized Andes assembly ldexpf  (test_ldexpf_opt.elf)
 *   2. Linked with toolchain's default ldexpf        (test_ldexpf_ref.elf)
 * Run both, diff the output to find discrepancies.
 */

#include <math.h>
#include <stdint.h>
#include <stdio.h>
#include <float.h>

#ifdef EN_PERF
#define PF_COUNTER
#include "nds_pfcounter.h"
#endif

static inline uint32_t f2u(float f)
{
    union { float f; uint32_t u; } x;
    x.f = f;
    return x.u;
}

static inline float u2f(uint32_t u)
{
    union { float f; uint32_t u; } x;
    x.u = u;
    return x.f;
}

#ifdef EN_PERF
static volatile float g_acc;

static void emit(float x, int exp)
{
    volatile float vx = x;   /* prevent constant-folding of literal arguments */
    g_acc += ldexpf(vx, exp);
}

static void emit_u(uint32_t bits, int exp)
{
    emit(u2f(bits), exp);
}
#else
static void emit(float x, int exp)
{
    float r = ldexpf(x, exp);
    printf("%08lx %d %08lx\n",
           (unsigned long)f2u(x), exp, (unsigned long)f2u(r));
}

static void emit_u(uint32_t bits, int exp)
{
    emit(u2f(bits), exp);
}
#endif

/* ------------------------------------------------------------------ */
/* Representative 100-point test                                       */
/* ------------------------------------------------------------------ */

static void test_representative_100(void)
{
    /* --- Section 1: Special IEEE 754 values for x (7) --- */
    emit(0.0f, 0);                    /* +zero, n=0 -> +zero */
    emit(-0.0f, 0);                   /* -zero, n=0 -> -zero */
    emit_u(0x7fc00000u, 5);           /* qNaN -> qNaN */
    emit_u(0x7f800001u, 5);           /* sNaN -> NaN */
    emit_u(0xffc00000u, 5);           /* -qNaN -> -qNaN */
    emit_u(0x7f800000u, 5);           /* +Inf * 2^5 -> +Inf */
    emit_u(0xff800000u, 5);           /* -Inf * 2^5 -> -Inf */

    /* --- Section 2: Subnormal x values (6) --- */
    emit_u(0x00000001u, 0);           /* min positive subnormal: 2^-149, n=0 */
    emit_u(0x80000001u, 0);           /* min negative subnormal, n=0 */
    emit_u(0x00400000u, 0);           /* mid positive subnormal, n=0 */
    emit_u(0x80400000u, 0);           /* mid negative subnormal, n=0 */
    emit_u(0x007fffffu, 0);           /* max subnormal: just below FLT_MIN, n=0 */
    emit_u(0x807fffffu, 0);           /* max negative subnormal, n=0 */

    /* --- Section 3: Normal boundary x values (6) --- */
    emit_u(0x00800000u, 0);           /* FLT_MIN = 2^-126, n=0 */
    emit_u(0x80800000u, 0);           /* -FLT_MIN, n=0 */
    emit_u(0x00800001u, 0);           /* one ULP above FLT_MIN, n=0 */
    emit_u(0x7f7fffffu, 0);           /* FLT_MAX, n=0 */
    emit_u(0xff7fffffu, 0);           /* -FLT_MAX, n=0 */
    emit_u(0x7f7ffffeu, 0);           /* one ULP below FLT_MAX, n=0 */

    /* --- Section 4: Near 1.0 x values (6) --- */
    emit_u(0x3f7fffffu, 0);           /* one ULP below 1.0, n=0 */
    emit(1.0f, 0);                    /* 1.0 * 2^0 = 1.0 */
    emit_u(0x3f800001u, 0);           /* one ULP above 1.0, n=0 */
    emit(-1.0f, 0);                   /* -1.0 * 2^0 = -1.0 */
    emit_u(0xbf7fffffu, 0);           /* one ULP toward zero from -1.0 */
    emit_u(0xbf800001u, 0);           /* one ULP away from zero from -1.0 */

    /* --- Section 5: Overflow cases (large positive n) (8) --- */
    emit(1.0f, 127);                  /* 1.0 * 2^127 = FLT_MAX exponent zone */
    emit(1.0f, 128);                  /* 1.0 * 2^128 -> overflow to +Inf */
    emit(0.5f, 128);                  /* 0.5 * 2^128 = 2^127 = max representable */
    emit(0.5f, 129);                  /* overflow */
    emit(-1.0f, 128);                 /* -1.0 * 2^128 -> -Inf */
    emit(1.0f, 200);                  /* very large n -> +Inf */
    emit(-1.0f, 200);                 /* very large n -> -Inf */
    emit_u(0x7f7fffffu, 1);           /* FLT_MAX * 2 -> overflow */

    /* --- Section 6: Underflow cases (large negative n) (8) --- */
    emit(1.0f, -127);                 /* 1.0 * 2^-127 = subnormal region */
    emit(1.0f, -149);                 /* 1.0 * 2^-149 = min positive subnormal */
    emit(1.0f, -150);                 /* underflow to zero */
    emit(-1.0f, -150);                /* underflow to -zero */
    emit(1.0f, -200);                 /* deep underflow -> +zero */
    emit(-1.0f, -200);                /* deep underflow -> -zero */
    emit_u(0x00800000u, -1);          /* FLT_MIN * 2^-1 = max subnormal */
    emit_u(0x00000001u, -1);          /* min subnormal * 2^-1 -> zero (underflow) */

    /* --- Section 7: Normal-to-subnormal (gradual underflow) (10) --- */
    emit_u(0x00800000u, 0);           /* FLT_MIN: already at boundary */
    emit_u(0x00800000u, -1);          /* FLT_MIN * 2^-1: first subnormal */
    emit_u(0x00800000u, -2);          /* FLT_MIN * 2^-2 */
    emit_u(0x00800000u, -10);         /* FLT_MIN * 2^-10 */
    emit_u(0x00800000u, -23);         /* FLT_MIN * 2^-23: approaching min subnormal */
    emit_u(0x01000000u, -24);         /* 2*FLT_MIN * 2^-24 = min subnormal */
    emit_u(0x01000000u, -25);         /* below min subnormal -> zero */
    emit(1.5f, -149);                 /* 1.5 * 2^-149 = 1 ULP subnormal */
    emit(1.5f, -126);                 /* 1.5 * 2^-126: just above FLT_MIN */
    emit(1.5f, -127);                 /* 1.5 * 2^-127 = subnormal */

    /* --- Section 8: Subnormal-to-normal (positive n shifts into normal range) (8) --- */
    emit_u(0x00000001u, 149);         /* min subnormal * 2^149 = 1.0 */
    emit_u(0x00000001u, 148);         /* min subnormal * 2^148 = 0.5 */
    emit_u(0x007fffffu, 1);           /* max subnormal * 2 = just below FLT_MIN */
    emit_u(0x007fffffu, 2);           /* max subnormal * 4 -> normal */
    emit_u(0x00400000u, 1);           /* mid subnormal * 2 */
    emit_u(0x00400000u, 2);           /* mid subnormal * 4 */
    emit_u(0x80000001u, 149);         /* min neg subnormal * 2^149 = -1.0 */
    emit_u(0x807fffffu, 2);           /* max neg subnormal * 4 -> negative normal */

    /* --- Section 9: Identity n=0 with varied normal x (10) --- */
    emit(0.1f, 0);                    /* 0.1 * 1 = 0.1 */
    emit(0.5f, 0);                    /* 0.5 */
    emit(1.5f, 0);                    /* 1.5 */
    emit(2.0f, 0);                    /* 2.0 */
    emit(10.0f, 0);                   /* 10.0 */
    emit(100.0f, 0);                  /* 100.0 */
    emit(-0.5f, 0);                   /* -0.5 */
    emit(-1.5f, 0);                   /* -1.5 */
    emit(-10.0f, 0);                  /* -10.0 */
    emit(-100.0f, 0);                 /* -100.0 */

    /* --- Section 10: Exponent sweep with varied bases (31) --- */
    /* n = -10 to +10 with base 1.0 (21 points) */
    emit(1.0f, -10);
    emit(1.0f, -9);
    emit(1.0f, -8);
    emit(1.0f, -7);
    emit(1.0f, -6);
    emit(1.0f, -5);
    emit(1.0f, -4);
    emit(1.0f, -3);
    emit(1.0f, -2);
    emit(1.0f, -1);
    emit(1.0f, 1);
    emit(1.0f, 2);
    emit(1.0f, 3);
    emit(1.0f, 4);
    emit(1.0f, 5);
    emit(1.0f, 6);
    emit(1.0f, 7);
    emit(1.0f, 8);
    emit(1.0f, 9);
    emit(1.0f, 10);
    /* Additional bases with varied n (10 points) */
    emit(0.75f, -1);                  /* 0.75 * 0.5 = 0.375 */
    emit(0.75f, 1);                   /* 0.75 * 2 = 1.5 */
    emit(1.5f, -1);                   /* 1.5 * 0.5 = 0.75 */
    emit(1.5f, 1);                    /* 1.5 * 2 = 3.0 */
    emit(-0.75f, 2);                  /* -0.75 * 4 = -3.0 */
    emit(-1.5f, -2);                  /* -1.5 * 0.25 = -0.375 */
    emit(1.0f, 126);                  /* large but not overflow */
    emit(1.0f, -126);                 /* small but still normal */
    emit(0.5f, 127);                  /* 0.5 * 2^127 = FLT_MAX / 2 */
    emit(-0.5f, 127);                 /* -0.5 * 2^127 */
}

/* ------------------------------------------------------------------ */

int main(void)
{
#ifdef EN_PERF
    startPFM;
    test_representative_100();
    stopPFM;
    readResult();
    printf("perf g_acc: %08lx\n", (unsigned long)f2u((float)g_acc));
#else
    test_representative_100();
    test_exhaustive_small();
#endif
    return 0;
}

/* ------------------------------------------------------------------ */
/* Dense sweep (accuracy path only)                                   */
/* ------------------------------------------------------------------ */

#ifndef EN_PERF
/* Sample mantissa [0.5, 1) with base exponent */
static void test_exhaustive_small(void)
{
    uint32_t start = 0x3f000000u; /* 0.5 */
